namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime CreatedAt { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Exception
}

namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber);
    Task<Shipment?> UpdateStatusAsync(int id, ShipmentStatus status);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment?> UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var response = await _http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await _http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ShipmentServerService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _db.Shipments.OrderByDescending(s => s.CreatedAt).ToListAsync();
    }

    public async Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        return await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment?> UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await _db.Shipments.FindAsync(id);
        if (shipment is null) return null;
        shipment.Status = status;
        await _db.SaveChangesAsync();
        return shipment;
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        shipment.TrackingNumber = $"SHP-{Guid.NewGuid().ToString()[..8].ToUpper()}";
        shipment.CreatedAt = DateTime.UtcNow;
        _db.Shipments.Add(shipment);
        await _db.SaveChangesAsync();
        return shipment;
    }
}

using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("/", async (IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync()))
            .RequireAuthorization();

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        }).RequireAuthorization();

        group.MapPut("/{id}/status", async (int id, ShipmentStatus status, IShipmentService service) =>
        {
            var shipment = await service.UpdateStatusAsync(id, status);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        }).RequireAuthorization();

        group.MapPost("/", async (Shipment shipment, IShipmentService service) =>
            Results.Created($"/api/shipments/{shipment.Id}", await service.CreateShipmentAsync(shipment)))
            .RequireAuthorization();
    }
}

