@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments - Dispatcher Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Description</label>
                    <input class="form-control" @bind="newShipment.Description" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Origin</label>
                    <input class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Destination</label>
                    <input class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Customer Email</label>
                    <input class="form-control" @bind="newShipment.CustomerEmail" />
                </div>
            </div>
            <div class="row g-3 mt-1">
                <div class="col-md-3">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="estimatedDelivery" />
                </div>
                <div class="col-auto align-self-end">
                    <button class="btn btn-success" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary ms-2" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found. Create one to get started.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Description</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in shipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Description</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status" @onchange="e => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private bool showCreateForm;
    private Shipment newShipment = new();
    private DateTime? estimatedDelivery;

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new();
        estimatedDelivery = DateTime.Today.AddDays(5);
    }

    private async Task CreateShipment()
    {
        newShipment.EstimatedDelivery = estimatedDelivery;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        showCreateForm = false;
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            if (updated is not null)
            {
                shipment.Status = updated.Status;
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g., SHP-A1B2C3D4)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
        </div>
    </div>
</div>

@if (isLoading)
{
    <p><em>Searching...</em></p>
}
else if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number "<strong>@searchedNumber</strong>". Please check the number and try again.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5">@(shipment.EstimatedDelivery?.ToString("MMMM dd, yyyy") ?? "Not yet scheduled")</dd>
                        <dt>Created</dt>
                        <dd>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</dd>
                    </dl>
                </div>
            </div>

            <div class="mt-3">
                <h6>Delivery Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar" style="width: @(GetProgressPercent(shipment.Status))%">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool isLoading;
    private bool searched;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        searched = false;
        shipment = null;

        try
        {
            searchedNumber = trackingNumber.Trim();
            shipment = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
            searched = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await TrackShipment();
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Exception => 50,
        _ => 0
    };
}

