namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ShipmentServerService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _db.Shipments.OrderByDescending(s => s.CreatedAt).ToListAsync();
    }

    public async Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        return await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment?> UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await _db.Shipments.FindAsync(id);
        if (shipment is null) return null;
        shipment.Status = status;
        await _db.SaveChangesAsync();
        return shipment;
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        shipment.TrackingNumber = $"SHP-{Guid.NewGuid().ToString()[..8].ToUpper()}";
        shipment.CreatedAt = DateTime.UtcNow;
        _db.Shipments.Add(shipment);
        await _db.SaveChangesAsync();
        return shipment;
    }
}
